// Logos como constantes base64
// Para produção: mover para /public e usar next/image
export const LOGOS = {
  fb:     "",
  care:   "",
  clinic: "",
  engine: "",
} as const;

export type LogoKey = keyof typeof LOGOS;

interface LogoProps {
  logo: LogoKey;
  height?: number;
  alt?: string;
  className?: string;
  style?: React.CSSProperties;
}

export function FractaLogo({ logo, height = 36, alt, className, style }: LogoProps) {
  return (
    <img
      src={`data:image/png;base64,${LOGOS[logo]}`}
      alt={alt ?? logo}
      height={height}
      style={{ height, width: "auto", ...style }}
      className={className}
    />
  );
}
